            sourceUrl2: 'https://www.bbc.com/news/articles/germany-afd-extremist-classification-2025',
            sourceSnippet2: 'Germany classifies AfD as extremist group — BBC News, May 2025',
            source3: 'DW (Deutsche Welle)',
            sourceUrl3: 'https://www.dw.com/en/afd-legal-challenge-verfassungsschutz-classification/a-72567890',
            sourceSnippet3: 'AfD challenges extremist classification in court — DW, 2025',
            source4: 'The Guardian',
            sourceUrl4: 'https://www.theguardian.com/world/2025/may/02/germany-afd-far-right-extremist-designation-ban-debate',
